541→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
542→  LET $query = string::lowercase(string::trim($q));
543→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
544→
545→  LET $task_rows = SELECT
546→    id,
547→    "task" AS kind,
548→    title AS text,
549→    extraction_confidence AS confidence,
550→    source_message AS sourceMessage,
551→    priority,
552→    created_at
553→  FROM task
554→  WHERE workspace = $workspace
555→    AND extraction_confidence != NONE
556→    AND string::contains(string::lowercase(title), $query)
557→  ORDER BY created_at DESC
558→  LIMIT $safe_limit;
559→
560→  LET $decision_rows = SELECT
561→    id,
562→    "decision" AS kind,
563→    summary AS text,
564→    extraction_confidence AS confidence,
565→    source_message AS sourceMessage,
566→    priority,
567→    created_at
568→  FROM decision
569→  WHERE workspace = $workspace
570→    AND extraction_confidence != NONE
571→    AND string::contains(string::lowercase(summary), $query)
572→  ORDER BY created_at DESC
573→  LIMIT $safe_limit;
574→
575→  LET $question_rows = SELECT
576→    id,
577→    "question" AS kind,
578→    text AS text,
579→    extraction_confidence AS confidence,
580→    source_message AS sourceMessage,
581→    priority,
582→    created_at
583→  FROM question
584→  WHERE workspace = $workspace
585→    AND extraction_confidence != NONE
586→    AND string::contains(string::lowercase(text), $query)
587→  ORDER BY created_at DESC
588→  LIMIT $safe_limit;
589→
590→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
591→};
