667→DEFINE FUNCTION fn::entity_edges($entity: record, $lim: int) {
668→  RETURN SELECT id, `in`, out, kind, confidence
669→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
670→         depends_on, owns, observes, suggests_for, subtask_of
671→    WHERE `in` = $entity OR out = $entity
672→    LIMIT $lim;
