675→DEFINE FUNCTION fn::edges_between($ids: array) {
676→  RETURN SELECT id, `in`, out, kind, confidence
677→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
678→         depends_on, owns, observes, suggests_for, subtask_of
679→    WHERE `in` IN $ids AND out IN $ids;
