682→DEFINE FUNCTION fn::graph_neighbors($ids: array) {
683→  RETURN SELECT `in`, out
684→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
685→         depends_on, owns, observes, suggests_for, subtask_of
686→    WHERE `in` IN $ids OR out IN $ids;
