689→DEFINE FUNCTION fn::workspace_entity_ids($ws: record<workspace>) {
690→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
691→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
692→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
693→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
694→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
695→  LET $persons = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
696→  LET $provenance = (
697→    SELECT VALUE out FROM extraction_relation
698→    WHERE `in` IN (
699→      SELECT VALUE id FROM message
700→      WHERE conversation IN (
701→        SELECT VALUE id FROM conversation WHERE workspace = $ws
702→      )
703→    )
704→  );
705→  RETURN array::distinct(
706→    $projects + $features + $tasks +
707→    $belongs_project + $belongs_feature +
708→    $persons + $provenance
709→  );
710→};
711→
712→DEFINE FUNCTION fn::project_entity_ids($ws: record<workspace>, $project: record<project>) {
713→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` = $project);
714→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
715→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out = $project);
716→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
717→  LET $persons = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
718→  LET $provenance = (
719→    SELECT VALUE out FROM extraction_relation
720→    WHERE `in` IN (
721→      SELECT VALUE id FROM message
722→      WHERE conversation IN (
723→        SELECT VALUE id FROM conversation WHERE workspace = $ws
724→      )
725→    )
726→  );
727→  RETURN array::distinct(
728→    [$project] + $features + $tasks +
729→    $belongs_project + $belongs_feature +
730→    $persons + $provenance
731→  );
732→};
