202→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
203→  const startedAt = performance.now();
204→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
205→
206→  try {
207→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
208→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
209→    if (!workspace) {
210→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
211→    }
212→
213→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
214→    const conversationId = conversationRecord.id as string;
215→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
216→
217→    const messages = rawMessages.map((row) => ({
218→      id: row.id,
219→      role: row.role,
220→      text: row.text,
221→      createdAt: toIsoString(row.createdAt),
222→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
223→      ...(row.inherited ? { inherited: true } : {}),
224→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
225→    } satisfies WorkspaceBootstrapMessage));
226→
227→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
228→    const onboardingState = toOnboardingState(workspace);
229→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
230→
231→    const payload: WorkspaceBootstrapResponse = {
232→      workspaceId: workspace.id.id as string,
233→      workspaceName: workspace.name,
234→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
235→      ...(workspace.repo_path ? { repoPath: workspace.repo_path } : {}),
236→      onboardingComplete: workspace.onboarding_complete,
237→      onboardingState,
238→      conversationId: conversationRecord.id as string,
239→      messages,
240→      seeds,
241→      sidebar,
242→    };
243→
244→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
245→      workspaceId,
246→      conversationId: conversationRecord.id as string,
247→      messageCount: messages.length,
248→      seedCount: seeds.length,
249→      durationMs: elapsedMs(startedAt),
250→    });
251→
252→    return jsonResponse(payload, 200);
253→  } catch (error) {
254→    if (error instanceof HttpError) {
255→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
256→        workspaceId,
257→        statusCode: error.status,
258→      });
259→      return jsonError(error.message, error.status);
260→    }
261→
262→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
263→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
264→    return jsonError(errorText, 500);
265→  }
266→}
