422→async function handleWorkspaceConversation(
423→  deps: ServerDependencies,
424→  workspaceId: string,
425→  conversationId: string,
426→): Promise<Response> {
427→  const startedAt = performance.now();
428→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
429→    workspaceId,
430→    conversationId,
431→  });
432→
433→  try {
434→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
435→    const conversationRecord = new RecordId("conversation", conversationId);
436→    const conversation = await deps.surreal.select<{
437→      id: RecordId<"conversation", string>;
438→      workspace: RecordId<"workspace", string>;
439→      discusses?: RecordId;
440→    }>(conversationRecord);
441→
442→    if (!conversation) {
443→      throw new HttpError(404, `conversation not found: ${conversationId}`);
444→    }
445→
446→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
447→      throw new HttpError(400, "conversation does not belong to workspace");
448→    }
449→
450→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
451→
452→    const messages = rawMessages.map((row) => ({
453→      id: row.id,
454→      role: row.role,
455→      text: row.text,
456→      createdAt: toIsoString(row.createdAt),
457→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
458→      ...(row.inherited ? { inherited: true } : {}),
459→      ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagentTraces: row.subagent_traces } : {}),
460→    } satisfies WorkspaceBootstrapMessage));
461→
462→    let discussEntity: DiscussEntitySummary | undefined;
463→    if (conversation.discusses) {
464→      const entityRecord = conversation.discusses as GraphEntityRecord;
465→      const name = await readEntityName(deps.surreal, entityRecord);
466→      if (name) {
467→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
468→        discussEntity = {
469→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
470→          kind: entityRecord.table.name as EntityKind,
471→          name,
472→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
473→        };
474→      }
475→    }
476→
477→    const payload: WorkspaceConversationResponse = {
478→      conversationId,
479→      messages,
480→      ...(discussEntity ? { discussEntity } : {}),
481→    };
482→
483→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
484→      workspaceId,
485→      conversationId,
486→      messageCount: messages.length,
487→      durationMs: elapsedMs(startedAt),
488→    });
489→
490→    return jsonResponse(payload, 200);
491→  } catch (error) {
492→    if (error instanceof HttpError) {
493→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
494→        workspaceId,
495→        conversationId,
496→        statusCode: error.status,
497→      });
498→      return jsonError(error.message, error.status);
499→    }
500→
501→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
502→      workspaceId,
503→      conversationId,
504→    });
505→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
506→    return jsonError(errorText, 500);
507→  }
508→}
