514→async function handleUpdateRepoPath(
515→  deps: ServerDependencies,
516→  workspaceId: string,
517→  request: Request,
518→  shellExec?: ShellExec,
519→): Promise<Response> {
520→  const startedAt = performance.now();
521→  logInfo("workspace.repo_path.update.started", "Repo path update started", { workspaceId });
522→
523→  try {
524→    let body: unknown;
525→    try {
526→      body = await request.json();
527→    } catch {
528→      return jsonError("Request body must be valid JSON", 400);
529→    }
530→
531→    if (!body || typeof body !== "object") {
532→      return jsonError("Body must be an object", 400);
533→    }
534→
535→    const { path: rawPath } = body as { path?: string };
536→    if (!rawPath || typeof rawPath !== "string" || rawPath.trim().length === 0) {
537→      return jsonError("path is required", 400);
538→    }
539→
540→    if (!shellExec) {
541→      return jsonError("shell execution not available", 500);
542→    }
543→
544→    const trimmedPath = rawPath.trim();
545→
546→    const repoValidation = await validateRepoPath(trimmedPath, shellExec);
547→    if (!repoValidation.ok) {
548→      return jsonError(repoValidation.error, 400);
549→    }
550→
551→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
552→
553→    await deps.surreal.query(
554→      "UPDATE $workspace SET repo_path = $repoPath, updated_at = time::now();",
